#include<cstdio>
#include<cstring>
#include<iostream>
using namespace std;


int main(){
    int n;
    cin>>n;
    int all = 0;
    int angry = 0;
    int course [n] [2];

    for (int j = 0; j < n; j++)
    {
        cin>>course [j][0]>>course [j][1];
       angry = angry + course [j] [0] + course [j] [1] - 8;
       all += angry;
    }
    cout<< all;
}
